import os
import psutil
import time

def get_used_files(directory):
    used_files = []
    for proc in psutil.process_iter(['pid', 'name']):
        try:
            p = proc.info
            if p['name']!='system':
                for root, dirs, files in os.walk(directory):
                    for file in files:
                        file_path = os.path.join(root, file)
                        if os.path.exists(file_path):
                            used_files.append(file_path)
        except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
            pass
    return used_files

def delete_unused_files(directory):
    used_files = get_used_files(directory)
    for file in os.listdir(directory):
        file_path = os.path.join(directory, file)
        if file not in used_files:
            try:
                os.remove(file_path)
                print(f"Deleted file: {file_path}")
            except Exception as e:
                print(f"Error deleting file: {file_path} - {e}")

def main():
    directory = os.path.expanduser('~')  # Get the user's home directory
    print(f"Cleaning up {directory}...")
    delete_unused_files(directory)
    print("Done cleaning up!")

if __name__ == "__main__":
    main()
